return [avatars[randomIndex]];

const avatars = items;

if (!avatars.length) {
  throw new Error('No avatars found');
}

const randomIndex = Math.floor(Math.random() * avatars.length);
return [avatars[randomIndex]];

const norm = v => String(v ?? '').trim().toLowerCase();

const seen = {};
const toDelete = [];

for (const { json } of items) {
  const link = norm(json.Link);
  if (!link) continue;

  if (!seen[link]) {
    seen[link] = json;
    continue;
  }

  // duplicate found → delete this one
  toDelete.push(json);
}

return toDelete.map(r => ({ json: { id: r.id }}));

